  if (window.__stayOnScreenGuard) return true;
  window.__stayOnScreenGuard = true;

  // 1) Prevenir cualquier submit automático del formulario (captura)
  const preventSubmit = (ev) => {
    ev.preventDefault();
    ev.stopImmediatePropagation();
    console.log("⛔ submit prevenido — permaneciendo en el screen");
    // delay opcional para asegurar que el DOM muestre tu mensaje
    setTimeout(() => {}, 300);
  };
  document.addEventListener("submit", preventSubmit, true);

  // 2) Bloquear navegación SPA (Vue Router) temporalmente
  const origPush = history.pushState;
  const origReplace = history.replaceState;
  history.pushState = function () {
    console.log("⛔ pushState bloqueado");
    return; // no navegues
  };
  history.replaceState = function () {
    console.log("⛔ replaceState bloqueado");
    return; // no navegues
  };

  // 3) Evitar que el navegador intente descargar/recargar (fallback)
  const blockUnload = (e) => {
    e.preventDefault();
    e.returnValue = ""; // muestra prompt nativo si intentan salir
    return "";
  };
  window.addEventListener("beforeunload", blockUnload);

  // 4) Ventana de tiempo: mantener el screen visible N segundos y luego liberar
  const HOLD_MS = 15000; // <- ajusta el tiempo que quieres mantener en pantalla
  setTimeout(() => {
    document.removeEventListener("submit", preventSubmit, true);
    window.removeEventListener("beforeunload", blockUnload);
    history.pushState = origPush;
    history.replaceState = origReplace;
    console.log("✅ Guard levantado: si el usuario quiere, ya puede navegar/cerrar.");
  }, HOLD_MS);

  // La Propiedad Calculada debe devolver algo
  return true;

function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

(async () => {
  await sleep(3000); // si quieres esperar un poquito, opcional

  if (window.confirm('Tu solicitud se ha enviado correctamente. Al aceptar puedes cerrar esta pestaña.')) {
    // Solo funcionará si la pestaña fue abierta con window.open
    if (window.opener) {
      window.close();
    }
  }
})();

